// ==============================================
// PASTE YOUR FULL DEMO TRANSCRIPT BELOW
// ==============================================

const transcript = `
Speaker 1: 00:00 
 All right, we'll let Ben in now in three, two, one. And he's in.

Speaker 2: 00:16 
 Hey, Ben, can you hear me?

Speaker 3: 00:22 
 Wait, can you hear me? Yeah.

[PASTE YOUR COMPLETE DEMO TRANSCRIPT HERE]
`;

return {
  json: {
    account_id: "bens_electric_solutions",
    transcript: transcript
  }
};

const transcript = $input.first().json.transcript;
const truncated = transcript.substring(0, 12000);

const systemMsg = "You extract business info from sales demo calls. Return ONLY valid JSON, no markdown, no code blocks.";

const userMsg = `Extract from this transcript. If not mentioned, use null.

Return this EXACT JSON:
{
  "company_name": "string or null",
  "owner_name": "string or null",
  "email": "string or null",
  "phone": "string or null",
  "address": "string or null",
  "crm_system": "string or null",
  "team_size": "number or null",
  "num_trucks": "number or null",
  "has_subcontractors": "boolean or null",
  "owner_role": "string or null",
  "services_offered": ["list of services"],
  "services_not_offered": ["list"],
  "handles_emergency_calls": "boolean or null",
  "emergency_policy": "string or null",
  "business_hours": "string or null",
  "after_hours_policy": "string or null",
  "service_call_fee": "string or null",
  "hourly_rate": "string or null",
  "plan_name": "string or null",
  "monthly_cost": "number or null",
  "term_months": "number or null",
  "questions_or_unknowns": ["list"],
  "summary": "1-2 sentence summary"
}

TRANSCRIPT:
${truncated}`;

const requestBody = {
  model: "llama-3.1-8b-instant",
  messages: [
    { role: "system", content: systemMsg },
    { role: "user", content: userMsg }
  ],
  temperature: 0.1,
  max_tokens: 2000
};

return {
  json: {
    requestBody: requestBody,
    account_id: $input.first().json.account_id
  }
};

const account_id = $('Prepare Groq Request').first().json.account_id;
const resp = $input.first().json;

let content = resp.choices[0].message.content.trim();

// Clean JSON
if (content.startsWith('```json')) content = content.slice(7);
if (content.startsWith('```')) content = content.slice(3);
if (content.endsWith('```')) content = content.slice(0, -3);
content = content.trim();

let ext;
try {
  ext = JSON.parse(content);
} catch (e) {
  return { json: { error: 'JSON parse failed', raw: content.substring(0, 500) } };
}

// Build Account Memo v1
const memo = {
  account_id: account_id,
  company_name: ext.company_name,
  owner_name: ext.owner_name,
  email: ext.email,
  phone: ext.phone,

  business_hours: {
    days: ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday"],
    start: "08:30",
    end: "17:00",
    timezone: "America/Edmonton",
    raw: ext.business_hours
  },

  office_address: ext.address,
  services_supported: ext.services_offered || [],
  services_not_supported: ext.services_not_offered || [],

  emergency_definition: [],
  emergency_routing_rules: {
    primary_contact: null,
    fallback: "Take message, callback next business day",
    after_hours_emergency_only_for: []
  },

  non_emergency_routing_rules: {
    during_hours: "Collect info, schedule appointment",
    after_hours: ext.after_hours_policy || "Take message, callback next business day"
  },

  call_transfer_rules: {
    transfer_enabled: false,
    transfer_to: null,
    timeout_seconds: 30,
    retries: 2,
    if_transfer_fails: "Take message, assure callback"
  },

  integration_constraints: ext.crm_system ? [`CRM: ${ext.crm_system}`] : [],

  pricing: {
    service_call_fee: ext.service_call_fee,
    hourly_rate: ext.hourly_rate,
    disclose_policy: "Only if customer asks"
  },

  plan_selected: {
    plan_name: ext.plan_name,
    monthly_cost: ext.monthly_cost,
    term_months: ext.term_months
  },

  operations: {
    crm_system: ext.crm_system,
    team_size: ext.team_size,
    num_trucks: ext.num_trucks,
    has_subcontractors: ext.has_subcontractors,
    owner_role: ext.owner_role
  },

  questions_or_unknowns: ext.questions_or_unknowns || [],
  notes: ext.summary || "",

  _metadata: {
    version: "v1",
    created_at: new Date().toISOString(),
    source: "demo_call"
  }
};

return { json: { accountMemo: memo, extracted: ext } };

const { accountMemo } = $input.first().json;

const biz = accountMemo.company_name || "the company";
const owner = accountMemo.owner_name || "the owner";
const svcs = accountMemo.services_supported.join(", ") || "electrical services";
const excl = accountMemo.services_not_supported.join(", ");
const hrs = accountMemo.business_hours;
const bizHrs = `${hrs.days.join(", ")} ${hrs.start} - ${hrs.end}`;
const fee = accountMemo.pricing?.service_call_fee || "";
const rate = accountMemo.pricing?.hourly_rate || "";

// Build Retell-compatible system prompt
const systemPrompt = `You are Clara, an AI receptionist for ${biz}.

## CRITICAL RULES
- Never mention tools, functions, or system to caller
- Maximum 5 questions per call
- Only quote pricing if customer asks
- Never make up information

## BUSINESS INFO
- Company: ${biz}
- Owner: ${owner}
- Hours: ${bizHrs}
- Services: ${svcs}
${excl ? `- Does NOT offer: ${excl}` : ""}

## PRICING (only if asked)
${fee ? `- Service Call Fee: ${fee}` : ""}
${rate ? `- Hourly Rate: ${rate}` : ""}

## OFFICE HOURS CALL FLOW
1. GREETING: "Thank you for calling ${biz}, this is Clara. How can I help you today?"
2. COLLECT: Name, phone number, service address
3. UNDERSTAND: "Can you describe what you need done?"
4. SCHEDULE: "Do you have a preferred day and time?"
5. CONFIRM: Repeat details back
6. CLOSE: "Thank you for calling ${biz}. Have a great day!"

## AFTER HOURS CALL FLOW
1. GREETING: "Thank you for calling ${biz}. We're currently closed. Our hours are ${bizHrs}. How can I help?"
2. CHECK: "Is this an emergency?"
3. IF NOT EMERGENCY: Take message (name, phone, brief description)
4. ASSURE: "Someone will call you first thing tomorrow morning."
5. CLOSE: "Thank you for calling. Have a good evening!"

## CALL TRANSFER PROTOCOL
- Announce: "Let me connect you with someone who can help."
- If fails: "I couldn't reach them. Let me take your information for a callback."

## SPECIAL SITUATIONS
- SPAM/SALES: "We're not interested. Thank you." (end call)
- ANGRY CUSTOMER: "I understand your frustration. Let me have ${owner} call you directly."
- BILLING QUESTIONS: "I'll have someone call you about that. Can I get your number?"`;

// Build Preliminary Retell Agent Configuration
const agentSpec = {
  // Retell Agent Settings
  agent_name: `Clara - ${biz}`,
  voice_id: "11labs-Bella",
  language: "en-US",

  // Response Engine Config
  response_engine: {
    type: "retell-llm",
    system_prompt: systemPrompt
  },

  // Voice Settings
  voice_settings: {
    stability: 0.5,
    similarity_boost: 0.75
  },

  // Call Settings
  begin_message: `Thank you for calling ${biz}, this is Clara. How can I help you today?`,
  end_call_phrases: ["goodbye", "have a great day", "talk to you later"],

  // Business Configuration
  business_config: {
    company_name: biz,
    owner_name: owner,
    business_hours: accountMemo.business_hours,
    services_offered: accountMemo.services_supported,
    services_excluded: accountMemo.services_not_supported,
    pricing: accountMemo.pricing
  },

  // Call Handling
  call_handling: {
    transfer_enabled: false,
    transfer_number: null,
    transfer_timeout_seconds: 30,
    max_retries: 2,
    fallback_action: "Take message, assure callback"
  },

  // Notifications
  notifications: {
    email: accountMemo.email,
    sms: accountMemo.phone
  },

  // Special Contacts (VIP/Emergency)
  special_contacts: [],

  // Metadata
  _metadata: {
    version: "v1",
    status: "preliminary",
    created_at: new Date().toISOString(),
    source: "demo_call",
    account_id: accountMemo.account_id
  }
};

return { json: { accountMemo, agentSpec } };

const { accountMemo, agentSpec } = $input.first().json;

// Create Task Entry (simulating Asana/task tracker)
const task = {
  task_id: `TASK-${Date.now()}`,
  account_id: accountMemo.account_id,
  company_name: accountMemo.company_name,

  task_type: "demo_call_processed",
  status: "complete",

  pipeline: "Pipeline A: Demo -> V1",
  version: "v1",

  outputs: {
    account_memo: `outputs/${accountMemo.account_id}/v1/account_memo.json`,
    agent_spec: `outputs/${accountMemo.account_id}/v1/agent_spec.json`
  },

  created_at: new Date().toISOString(),
  created_by: "n8n_automation",

  next_action: "Await onboarding call for V2 update",

  notes: accountMemo.notes
};

return {
  json: {
    success: true,
    message: "Pipeline A Complete: Demo -> V1",

    // ====================================
    // OUTPUTS - Save these to local files
    // ====================================

    // Save to: outputs/bens_electric_solutions/v1/account_memo.json
    account_memo_v1: accountMemo,

    // Save to: outputs/bens_electric_solutions/v1/agent_spec.json
    agent_spec_v1: agentSpec,

    // Append to: tasks.json
    task: task,

    // ====================================
    // INSTRUCTIONS
    // ====================================
    save_instructions: [
      "1. Copy 'account_memo_v1' -> outputs/bens_electric_solutions/v1/account_memo.json",
      "2. Copy 'agent_spec_v1' -> outputs/bens_electric_solutions/v1/agent_spec.json",
      "3. Add 'task' to tasks.json array",
      "4. Run Onboarding -> V2 workflow next"
    ]
  }
};
